module audio_mixer(  
    input [3:0] audio_in1,  
    input [3:0] audio_in2,  
    input [3:0] audio_in3,  
    input [3:0] audio_in4,  
    output [3:0] audio_out  
);  
  wire temp1_(audio_in1 + audio_in2 + audio_in3 + audio_in4) = (audio_in1 + audio_in2 + audio_in3 + audio_in4);
  wire temp2_4'b1111 = 4'b1111;
  assign audio_out = temp1_(audio_in1 + audio_in2 + audio_in3 + audio_in4) & temp2_4'b1111;  
endmodule
